let stockDetailsJson = "{\"quoteSummary\":{\"result\":[{\"summaryProfile\":{\"address1\":\"One Central Plaza\",\"address2\":\"8th Floor 36 Dame Street\",\"city\":\"Dublin\",\"zip\":\"D02 K7K5\",\"country\":\"Ireland\",\"phone\":\"353 0 166 99020\",\"website\":\"https://www.amarincorp.com\",\"industry\":\"Drug Manufacturers - General\",\"industryKey\":\"drug-manufacturers-general\",\"industryDisp\":\"Drug Manufacturers - General\",\"sector\":\"Healthcare\",\"sectorKey\":\"healthcare\",\"sectorDisp\":\"Healthcare\",\"longBusinessSummary\":\"Amarin Corporation plc, a pharmaceutical company, engages in the commercialization and development of therapeutics for the treatment of cardiovascular diseases in the United States, Europe, and internationally. It offers VASCEPA, a prescription-only omega-3 fatty acid product, used as an adjunct to diet for reducing triglyceride levels in adult patients with severe hypertriglyceridemia. The company sells its products principally through wholesalers, selected regional wholesalers, and retail and mail order pharmacy providers. It has a collaboration with Mochida Pharmaceutical Co., Ltd. to develop and commercialize drug products and indications based on the active pharmaceutical ingredient in Vascepa, the omega-3 acid, EPA. The company was formerly known as Ethical Holdings plc and changed its name to Amarin Corporation plc in 1999. Amarin Corporation plc was incorporated in 1989 and is headquartered in Dublin, Ireland.\",\"fullTimeEmployees\":80,\"companyOfficers\":[],\"irWebsite\":\"http://investor.amarincorp.com/\",\"executiveTeam\":[],\"maxAge\":86400}}],\"error\":null}}"
